from pathlib import Path
from collections import Counter, defaultdict
import os

root = Path.home() / 'Desktop' / 'codex-0.118'
print(f'ROOT: {root}')
if not root.exists():
    print('ERROR: directory not found')
    raise SystemExit(0)

exclude = {'.git', 'node_modules', 'dist', 'build', 'target', '__pycache__', '.venv', 'venv', '.next', 'coverage', 'out'}
manifest_names = {
    'package.json', 'pnpm-workspace.yaml', 'yarn.lock', 'package-lock.json',
    'Cargo.toml', 'Cargo.lock', 'pyproject.toml', 'setup.py', 'requirements.txt',
    'go.mod', 'go.sum', 'pom.xml', 'build.gradle', 'Makefile'
}
source_exts = {'.rs','.ts','.tsx','.js','.jsx','.mjs','.cjs','.py','.go','.java','.kt','.swift','.cpp','.cc','.c','.h','.hpp','.cs','.rb','.php'}

print('\nTOP_LEVEL:')
for p in sorted(root.iterdir(), key=lambda x: x.name.lower())[:80]:
    kind = 'dir' if p.is_dir() else 'file'
    print(f'- {kind}: {p.name}')

print('\nMANIFESTS (depth<=4):')
found = []
for cur_root, dirs, files in os.walk(root):
    rel = Path(cur_root).relative_to(root)
    depth = len(rel.parts)
    dirs[:] = [d for d in dirs if d not in exclude]
    if depth > 4:
        dirs[:] = []
        continue
    for f in files:
        if f in manifest_names:
            found.append(str(Path(cur_root) / f))
for p in sorted(found)[:120]:
    print('-', p)
if not found:
    print('- none found')

ext_counts = Counter()
dir_ext_counts = defaultdict(Counter)
for cur_root, dirs, files in os.walk(root):
    dirs[:] = [d for d in dirs if d not in exclude]
    rel = Path(cur_root).relative_to(root)
    top = rel.parts[0] if rel.parts else '.'
    for f in files:
        ext = Path(f).suffix.lower()
        if ext in source_exts:
            ext_counts[ext] += 1
            dir_ext_counts[top][ext] += 1

print('\nSOURCE_EXTENSION_COUNTS:')
for ext, n in ext_counts.most_common(20):
    print(f'- {ext}: {n}')
if not ext_counts:
    print('- no common source extensions found')

print('\nTOP_SOURCE_DIRS:')
ranked = []
for d, c in dir_ext_counts.items():
    total = sum(c.values())
    if total:
        ranked.append((total, d, c.most_common(5)))
for total, d, common in sorted(ranked, reverse=True)[:12]:
    summary = ', '.join(f'{ext}:{n}' for ext, n in common)
    print(f'- {d}: total={total}; {summary}')
if not ranked:
    print('- no source dirs detected')
